    }

    public int getTransactionId() { return transactionId; }
    public double getAmount() { return amount; }
    public boolean validate() { return amount > 0; }
    public void pay() { System.out.println("Processing ₹" + amount); }
}

class CreditCard extends PaymentMethod {
    private String maskedCardNumber;
    public CreditCard(double amount, String cardNumber) {
        super(amount);
        this.maskedCardNumber = "****-****-****-" + cardNumber.substring(cardNumber.length() - 4);
    }
    @Override public boolean validate() { return amount <= 100000.0; }
    @Override public void pay() {
        System.out.println("Credit card " + maskedCardNumber + ": ₹" + amount + " [TXN #" + getTransactionId() + "]");
    }
}

class UPI extends PaymentMethod {
    private String upiId;
    public UPI(double amount, String upiId) {
        super(amount);
        this.upiId = upiId;
    }
    @Override public boolean validate() { return amount <= 100000.0 && upiId.contains("@"); }
    @Override public void pay() {
        System.out.println("UPI " + upiId + ": ₹" + amount + " [TXN #" + getTransactionId() + "]");
    }
}

class NetBanking extends PaymentMethod {
    private String bankCode;
    public NetBanking(double amount, String bankCode) {
        super(amount);
        this.bankCode = bankCode;
    }
    @Override public void pay() {
        System.out.println("Net Banking [" + bankCode + "]: ₹" + amount + " [TXN #" + getTransactionId() + "]");
    }
